const body = $input.first().json.body || $input.first().json;
const COUNTRIES = ['KR','TW','JP','US','TH'];
const CC = {KR:'рҹҮ°рҹҮ· н•ңкөӯ',TW:'рҹҮ№рҹҮј лҢҖл§Ң',JP:'рҹҮҜрҹҮө мқјліё',US:'рҹҮәрҹҮё лҜёкөӯ',TH:'рҹҮ№рҹҮӯ нғңкөӯ'};

const NX = ['nexon','nexon company','nexon corporation','nexon korea',
  'nexon korea corporation','nexon games','neople','neople inc',
  'toben studio','toben studio inc','nexon gt','embark studios',
  'nat games','mintrocket'];
function isNX(dev) {
  if (!dev) return false;
  const dl = dev.toLowerCase().trim();
  return NX.some(nx => dl.includes(nx));
}

const allNexon = [];
const summaries = [];
const genreStats = {};
let totalApple = 0, totalGoogle = 0;

for (const cc of COUNTRIES) {
  const d = body.countries?.[cc];
  if (!d || d.error) { summaries.push({cc, name:CC[cc], error: d?.error||'no data'}); continue; }
  const apple = d.apple || [], google = d.google || [];
  totalApple += apple.length;
  totalGoogle += google.length;
  const nxA = apple.filter(a => a.nexon || isNX(a.dev));
  const nxG = google.filter(a => a.nexon || isNX(a.dev));
  nxA.forEach(a => allNexon.push({...a, country:cc, store:'apple'}));
  nxG.forEach(a => allNexon.push({...a, country:cc, store:'google'}));
  const aSet = new Set(apple.map(a=>(a.name||'').toLowerCase()));
  const gSet = new Set(google.map(a=>(a.name||'').toLowerCase()));
  const common = [...aSet].filter(n=>n&&gSet.has(n));
  summaries.push({
    cc, name:CC[cc],
    apple:apple.length, google:google.length,
    nxApple:nxA.length, nxGoogle:nxG.length,
    common:common.length,
    appleBanners:apple.filter(a=>a.banner).length,
    googleBanners:google.filter(a=>a.banner).length
  });
  [...apple,...google].forEach(a => { if(a.genre) genreStats[a.genre]=(genreStats[a.genre]||0)+1; });
}

const nxMap = {};
allNexon.forEach(a => {
  const key = (a.name||'').toLowerCase().replace(/[в„ў:пјҡ\s]/g,'');
  if (!nxMap[key]) nxMap[key] = {...a, countries:new Set(), stores:new Set()};
  nxMap[key].countries.add(a.country);
  nxMap[key].stores.add(a.store);
});
const nexonList = Object.values(nxMap).map(a=>({
  name:a.name, dev:a.dev, rank:a.rank,
  countries:[...a.countries], stores:[...a.stores],
  banner:a.banner, genre:a.genre||'',
  bothStores:a.stores.size>=2
}));

const topGenres = Object.entries(genreStats)
  .sort((a,b)=>b[1]-a[1]).slice(0,5)
  .map(([genre,count])=>({genre,count}));

/* лҰ¬нҸ¬нҠё нҺҳмқҙм§Җ ліёл¬ё мғқм„ұ */
const summaryText = summaries.filter(s=>!s.error).map(s =>
  s.name+' вҖ” AS '+s.apple+' (л°°л„Ҳ '+s.appleBanners+') / GP '+s.google+' (л°°л„Ҳ '+s.googleBanners+') / NX: AS '+s.nxApple+' GP '+s.nxGoogle
).join('\n');

const nexonText = nexonList.length ? nexonList.map(n => {
  const st = n.stores.map(s=>s==='apple'?'рҹҚҺAS':'рҹҹўGP').join(' ');
  const fl = n.countries.map(c=>({KR:'рҹҮ°рҹҮ·',TW:'рҹҮ№рҹҮј',JP:'рҹҮҜрҹҮө',US:'рҹҮәрҹҮё',TH:'рҹҮ№рҹҮӯ'}[c]||c)).join(' ');
  const tags = [];
  if(n.banner) tags.push('рҹ”Ҙл°°л„Ҳ');
  if(n.bothStores) tags.push('вҡЎм–‘мӘҪ');
  return n.name+' вҖ” '+st+' | '+fl+' | #'+n.rank+' '+tags.join(' ');
}).join('\n') : 'н”јміҗл“ң м—ҶмқҢ';

const genreText = topGenres.map(g => g.genre+': '+g.count+'к°ң').join('\n');

const reportMarkdown = '## рҹ“Ҡ көӯк°Җлі„ нҳ„нҷ©\n\n'+summaryText+'\n\n## рҹҺҜ NEXON н”јміҗл“ң ('+nexonList.length+'к°ң)\n\n'+nexonText+'\n\n## рҹ“Ҳ мһҘлҘҙ Top 5\n\n'+genreText;

return [{
  json: {
    date: body.date || new Date().toISOString().slice(0,10),
    totalApple, totalGoogle, summaries, nexonList,
    nexonCount: nexonList.length,
    hasNexon: nexonList.length > 0,
    topGenres, summaryText, nexonText, genreText, reportMarkdown
  }
}];

